                                <td class=\"bord\"></td>
                            {% endif %}
                            <td class=\"bord\"></td>
                            {% if devis.zone == 'oui' %}
                                <td class=\"bord\"></td>
                            {% endif %}
                            <td class=\"bord\"></td>
                            {% if devis.aarem == 'oui' %}
