                                            </td>
                                        {% endif %}
                                    {% endif %}
                                {% endif %}
                            {% else %}
                                {% if devis.ptva == 'oui' or devis.ptva == 'susp' %}
                                    <td colspan=\"2\" class=\"bord\" style=\"text-align: right;\"><b>TOTAL HT SANS REMISE</b></td>
                                {% else %}
