                                        <td colspan=\"2\" class=\"bord\" style=\"text-align: right;\"><b>TOTAL HT SANS REMISE</b>
                                        </td>
                                    {% else %}
                                        <td colspan=\"2\" class=\"bord\" style=\"text-align: right;\"><b>TOTAL HT SANS REMISE</b>
                                        </td>
                                    {% endif %}
                                {% endif %}
