                        {% endfor %}
                    {% endfor %}
                    {% for bon in devis.bons %}
                        <tr>
                            <td style=\"text-align: center; min-width: 120px !important;\">Bon Nº {{ bon.numbon }}</td>
                            <td style=\"max-width:500px !important; min-width: 250px !important; text-align: left\"
                                colspan=\"2\">{{ bon.articlecomposer.designation }}</td>
                            }
                            <td style=\"text-align: center; min-width: 80px !important;\">{{ bon.articlecomposer.reference }}</td>
                            <td style=\"text-align: center\">{{ bon.articlecomposer.unite }}</td>
                            <td style=\"text-align: center; min-width: 120px !important;\">{{ bon.articlecomposer.pu|number_format(2, ',', ' ') }}</td>
                        </tr>
                        <tr style=\"background-color:#f8f9fa; font-weight: 700\">
                            <th style=\"text-align: center\">RÉF</th>
                            <th style=\"max-width:500px !important; min-width: 200px !important; text-align: left\">
                                DÉSIGNATION
                            </th>
                            }
                            <th style=\"text-align: center\">UNITÉ</th>
                            <th style=\"text-align: center\">QTÉ</th>
                            <th style=\"text-align: center; min-width: 120px !important;\">PRIX&nbsp;U.</th>
                            <th style=\"text-align: center; min-width: 120px !important;\">MONTANT HT</th>
                        </tr>
                        {% for lign in bon.lignes %}
                            {% if lign.groupe == null %}
                                <tr>
                                    <td style=\"text-align: center\">{{ lign.reference }}</td>
                                    <td>{{ lign.designation|raw }}</td>
                                    <td style=\"text-align: center\">{{ lign.unite }}</td>
                                    <td style=\"text-align: center\">{{ lign.quantite|number_format(2, ',', ' ') }}</td>
                                    <td style=\"text-align: center\">{{ lign.pu|number_format(2, ',', ' ') }}</td>
                                    <td style=\"text-align: center\">{{ (lign.pu * lign.quantite)|number_format(2, ',', ' ') }}</td>
                                </tr>
                            {% endif %}
                        {% endfor %}
                    {% endfor %}
                {% endif %}
            </table>
        {% endif %}
        {% if devis.type != \"cps\" %}
            <p style=\"clear: both\"></p>
            <br>
            <p style=\"text-align: left\">
                Arrêté le présent devis à la somme de:<br>
                <span><b>{{ devis.totalttc|craue_spellout('fr-FR') }} {{ devis.monnaie.code }}</b></span>
            </p><br>
            <p style=\"float: right; text-decoration: underline\">SIGNATURE AUTORISÉE</p><br><br><br>
            {% if devis.conditions is not null %}
                <p style=\"float: left; color: #4e73df;\"><u>INFORMATIONS ADDITIONNELLES</u></p>
                <p style=\"clear: both\"></p>
                <p style=\"color: #000000;\">{{ devis.conditions|raw }}</p>
            {% endif %}
        {% endif %}
    </div>
{% endif %}

{% if type == 'shushu' %}
    <div class=\"body\">

        <h4 class=\"bolo700 col-black\">DEVIS Nº {{ devis.iddevis }} | <span
                    class=\"col-pink\">ÉTAT: {% if devis.etat == \"valide\" %} VALIDÉ {% endif %} {% if devis.etat == \"save\" %} NON VALIDÉ {% endif %}</span>
        </h4>
        <br>
        <table class=\"table table-striped\">
            <tr>
                <td colspan=\"4\" class=\"bolo700 col-blue text-left h5\">BONS DE COMMANDE FOURNISSEURS VALIDÉS</td>
            </tr>
            <tr>
                <td class=\"bolo600 col-blue-grey\">Bon Nº</td>
                <td class=\"text-right bolo600 col-blue-grey\">Total HT</td>
                <td class=\"text-right bolo600 col-blue-grey\">Total TTC</td>
                <td class=\"text-left bolo600 col-blue-grey\">Fournisseur</td>
            </tr>
            {% set thbon = 0 %}
            {% set ttcbon = 0 %}
            {% for bon in devis.bons %}
                {% if bon.corbeille is null and bon.etat == \"valide\" %}
                    {% if bon.fournisseur is not null and bon.fournisseur.type == 1 %}
                        {% if bon.type == \"oui\" %}
                            {% set thbon = bon.totalht + thbon %}
                            {% set ttcbon = bon.totalttc + ttcbon %}
                        {% endif %}
                        {% if bon.type == \"non\" %}
                            {% set thbon =   thbon - bon.totalht %}
                            {% set ttcbon =  ttcbon - bon.totalttc %}
                        {% endif %}
                        <tr>
                            <td><a href=\"{{ path('editbon',{'id':bon.id , 'idchantier': bon.chantier.id}) }}\"
                                   class=\"col-black bolo700\">Nº {{ bon.numbon }}</a><br>
                            </td>
                            <td class=\"text-right\">{{ bon.totalht|number_format(2, ',', ' ') }}</td>
                            <td class=\"text-right\">{{ bon.totalttc|number_format(2, ',', ' ') }}</td>
                            <td class=\"text-left col-pink bolo600\" colspan=\"3\"
                                style=\"margin-left: 60px !important;\">
                                {% if bon.fournisseur %}
                                    {{ bon.fournisseur.fournisseur }}
                                {% endif %}
                            </td>
                        </tr>
                    {% endif %}
                    {% if bon.fournisseur is null %}
                        {% if bon.type == \"oui\" %}
                            {% set thbon = bon.totalht + thbon %}
                            {% set ttcbon = bon.totalttc + ttcbon %}
                        {% endif %}
                        {% if bon.type == \"non\" %}
                            {% set thbon =   thbon - bon.totalht %}
                            {% set ttcbon =  ttcbon - bon.totalttc %}
                        {% endif %}
                        <tr>
                            <td><a href=\"{{ path('editbon',{'id':bon.id , 'idchantier': bon.chantier.id}) }}\"
                                   class=\"col-black bolo700\">Nº {{ bon.numbon }}</a><br>
                            </td>
                            <td class=\"text-right col-blue-grey bolo700\">{{ bon.totalht|number_format(2, ',', ' ') }}</td>
                            <td class=\"text-right col-blue-grey bolo700\">{{ bon.totalttc|number_format(2, ',', ' ') }}</td>
                            <td class=\"text-right\"></td>
                        </tr>
                    {% endif %}
                {% endif %}
            {% endfor %}
            <tr>
                <td class=\"bolo700 col-black text-right\">TOTAUX</td>
                <td class=\"text-right  bolo700 col-black\">{{ thbon|number_format(2, ',', ' ') }}</td>
                <td class=\"text-right bolo700 col-black\">{{ ttcbon|number_format(2, ',', ' ') }}</td>
                <td class=\"text-right col-pink\"></td>
            </tr>
        </table>
        <table class=\"table table-striped\">
            <tr>
                <td colspan=\"4\" class=\"bolo700 col-blue text-left h5\">BONS DE COMMANDE PRESTATAIRES VALIDÉS</td>
            </tr>
            <tr>
                <td class=\"bolo600 col-blue-grey\">Bon Nº</td>
                <td class=\"text-right bolo600 col-blue-grey\">Total HT</td>
                <td class=\"text-right bolo600 col-blue-grey\">Total TTC</td>
                <td class=\"text-left bolo600 col-blue-grey\">Prestataire</td>
            </tr>
            {% set thebon = 0 %}
            {% set ttecbon = 0 %}
            {% for bon in devis.bons %}
                {% if bon.corbeille is null and bon.etat == \"valide\" %}
                    {% if bon.fournisseur is not null and bon.fournisseur.type == 3 %}
                        {% if bon.type != \"non\" %}
                            {% set thebon = bon.totalht + thebon %}
                            {% set ttecbon = bon.totalttc + ttecbon %}
                        {% endif %}
                        {% if bon.type == \"non\" %}
                            {% set thebon =   thebon - bon.totalht %}
                            {% set ttecbon =  ttecbon - bon.totalttc %}
                        {% endif %}
                        <tr>
                            <td><a href=\"{{ path('editbon',{'id':bon.id , 'idchantier': bon.chantier.id}) }}\"
                                   class=\"col-black bolo700\">Nº {{ bon.numbon }}</a><br>
                            </td>
                            <td class=\"text-right bolo600\">{{ bon.totalht|number_format(2, ',', ' ') }}</td>
                            <td class=\"text-right bolo600\">{{ bon.totalttc|number_format(2, ',', ' ') }}</td>
                            <td class=\"text-left col-pink bolo600\" colspan=\"3\"
                                style=\"margin-left: 60px !important;\">
                                {% if bon.fournisseur %}
                                    {{ bon.fournisseur.fournisseur }}
                                {% endif %}
                            </td>
                        </tr>
                    {% endif %}
                {% endif %}
            {% endfor %}
            <tr>
                <td class=\"bolo700 col-black text-right\">TOTAUX</td>
                <td class=\"text-right col-black bolo700\">{{ thebon|number_format(2, ',', ' ') }}</td>
                <td class=\"text-right col-black bolo700\">{{ ttecbon|number_format(2, ',', ' ') }}</td>
                <td class=\"text-right col-pink\"></td>
            </tr>
        </table>
        <table class=\"table table-striped\">
            <tr class=\"bg-light-green\">
                <td class=\"bolo700 col-orange h5\"></td>
                <td class=\"text-center col-white\">TOTAL HT</td>
                <td class=\"text-center col-white\">TOTAL TTC</td>
            </tr>
            <tr class=\"bg-light\">
                <td class=\"bolo700 col-blue-grey h5\">TOTAUX DEVIS</td>
                <td class=\"text-right col-blue-grey bolo700\">{{ devis.totalht|number_format(2, ',', ' ') }}</td>
                <td class=\"text-right col-blue-grey bolo700\">{{ devis.totalttc|number_format(2, ',', ' ') }}</td>
            </tr>
            <tr class=\"bg-light\">
                <td class=\"bolo700 col-blue-grey h5\">TOTAUX BONS DE COMMANDE</td>
                <td class=\"text-right col-blue-grey bolo700\">{{ (thbon + thebon)|number_format(2, ',', ' ') }}</td>
                <td class=\"text-right col-blue-grey bolo700\">{{ (ttcbon + ttecbon)|number_format(2, ',', ' ') }}</td>
            </tr>
            <tr class=\"bg-light\">
                <td class=\"bolo700 col-blue-grey h5\">MARGE</td>
                <td class=\"text-right col-black bolo700\">{{ (devis.totalht - (thbon + thebon))|number_format(2, ',', ' ') }}</td>
                <td class=\"text-right col-black bolo700\">{{ (devis.totalttc - (ttcbon + ttecbon))|number_format(2, ',', ' ') }}</td>
            </tr>
        </table>
        <table class=\"table table-striped\">
            <tr>
                <td colspan=\"6\" class=\"bolo700 col-blue text-left h5\">DÉCOMPTES</td>
            </tr>
            <tr>
                <td>Décompte Nº</td>
                <td>Facture Nº</td>
                <td class=\"text-center\">%</td>
                <td class=\"text-right\">Total HT</td>
                <td class=\"text-right\">Total TTC</td>
                <td class=\"text-right\">État</td>
            </tr>
            {% for dec in devis.decomptes %}
                <tr>
                    <td>
                        <a href=\"{{ path('editdecompte',{'id':dec.id , 'idchantier': dec.chantier.id}) }}\"
                           class=\"col-black bolo700\">Nº{{ dec.numdecompte }}
                        </a>
                    </td>
                    <td class=\"col-black bolo700\">{% if dec.facture %}{{ dec.facture.numfacture }}{% endif %}</td>
                    <td class=\"text-center col-blue-grey bolo700\">{{ dec.avancement|number_format(2, ',', ' ') }}%</td>
                    <td class=\"text-right col-blue-grey bolo700\">{{ dec.apayer|number_format(2, ',', ' ') }}</td>
                    <td class=\"text-right col-blue-grey bolo700\">{{ dec.ttc|number_format(2, ',', ' ') }}</td>
                    <td class=\"text-right bolo700\"><span
                                class=\"col-green\">{% if dec.etat == \"valide\" %}Validé{% endif %}</span> <span
                                class=\"col-pink\">{% if dec.etat == \"save\" %}Non validé{% endif %}</span></td>
                </tr>
            {% endfor %}
        </table>
        <table class=\"table table-striped\">
            <tr>
                <td colspan=\"5\" class=\"bolo700 col-blue text-left h5\">FACTURES</td>
            </tr>
            <tr>
                <td>Fac Nº</td>
                <td>Déc Nº</td>
                <td class=\"text-right\">Total HT</td>
                <td class=\"text-right\">Total TTC</td>
                <td class=\"text-right\">État</td>
            </tr>
            {% for fac in devis.chantier.factures %}
                {% if fac.devis and fac.devis.id  == devis.id %}
                    <tr>
                        <td>
                            <a href=\"{{ path('editfacture',{'id':fac.id , 'idchantier': fac.chantier.id}) }}\"
                               class=\"col-black bolo700\">Nº {{ fac.numfacture }}
                            </a>
                        </td>
                        <td class=\"col-black bolo700\">{% if fac.decompte %}{{ fac.decompte.numdecompte }}{% endif %}</td>
                        <td class=\"text-right col-blue-grey bolo700\">{{ fac.totalht|number_format(2, ',', ' ') }}</td>
                        <td class=\"text-right col-blue-grey bolo700\">{{ fac.totalttc|number_format(2, ',', ' ') }}</td>
                        <td class=\"text-right\">{% if fac.etat == \"valide\" %}<span
                                    class=\"col-blue\">Validée</span>{% endif %} {% if fac.etat == \"save\" %}<span
                                    class=\"col-pink\">Non validée</span>{% endif %}</td>
                    </tr>
                {% endif %}
                {% if fac.acompte and fac.acompte.devis.id  == devis.id %}
                    <tr>
                        <td>
                            <a href=\"{{ path('editfacture',{'id':fac.id , 'idchantier': fac.chantier.id}) }}\"
                               class=\"col-black bolo700\">Nº {{ fac.numfacture }}
                            </a>
                        </td>
                        <td>{% if fac.decompte %}{{ fac.decompte.numdecompte }}{% endif %}</td>
                        <td class=\"text-right col-blue-grey bolo700\">{{ fac.totalht|number_format(2, ',', ' ') }}</td>
                        <td class=\"text-right col-blue-grey bolo700\">{{ fac.totalttc|number_format(2, ',', ' ') }}</td>
                        <td class=\"text-right\">{% if fac.etat == \"valide\" %}<span
                                    class=\"col-blue bolo700\">Validée</span>{% endif %} {% if fac.etat == \"save\" %}<span
                                    class=\"col-pink bolo700\">Non validée</span>{% endif %}</td>
                    </tr>
                {% endif %}
            {% endfor %}
        </table>
        <table class=\"table table-striped\">
            <tr>
                <td colspan=\"5\" class=\"bolo700 col-blue text-left h5\">RÈGLEMENTS EFFECTUÉS</td>
            </tr>
            <tr>
                <td>Règlements</td>
                <td>Facture Nº</td>
                <td class=\"text-right\">SOLDE</td>
                <td class=\"text-right\">VERSÉE</td>
                <td class=\"text-right\">RESTE</td>
            </tr>

            {% for fac in devis.chantier.factures %}
                {% set yum = fac.totalttc %}
                {% set sol = fac.totalttc %}
                {% for rele in fac.relever %}
                    {% set yum = yum -  rele.montant %}
                    <tr>
                        <td class=\"col-blue bolo700\">{{ rele.versement }}</td>
                        <td>
                            <a href=\"{{ path('editfacture',{'id':rele.facture.id , 'idchantier': rele.facture.chantier.id}) }}\"
                               class=\"col-black bolo700\">Nº {{ rele.facture.numfacture }}
                            </a>
                        </td>
                        <td class=\"text-right col-blue-grey bolo700\">{{ sol|number_format(2, ',', ' ') }}</td>
                        <td class=\"text-right col-blue-grey bolo700\">{{ rele.montant|number_format(2, ',', ' ') }}</td>
                        <td class=\"text-right col-blue-grey bolo700\">{{ yum|number_format(2, ',', ' ') }}</td>
                    </tr>
                    {% set sol = yum %}
                {% endfor %}
            {% endfor %}
        </table>
        <table class=\"table-striped table-bordered display nowrap\" style=\"width: 100%; margin-top: 30px\">
            <tr>
                <td colspan=\"5\" class=\"bolo700 col-blue text-left h5\">ARTICLES COMPOSÉS</td>
            </tr>
            <tr class=\"text-center\">
                <th>ARTICLES</th>
                <th class=\"text-center\">U</th>
                <th class=\"text-center\">QTÉ</th>
                <th>PU</th>
                <th class=\"text-center\">P. HT</th>
            </tr>
            {% for ligne in devis.lignes %}
                <tr>
                    <td style=\"padding: 2px !important; font-weight: bold\">{{ ligne.designation|raw }}</td>
                    <td style=\"padding: 2px !important; text-align: right ; font-weight: bold\"
                        class=\"col-blue\">{{ ligne.unite }}</td>
                    <td style=\"padding: 2px !important; text-align: right; white-space: nowrap ; font-weight: bold\"
                        class=\"col-blue\">{{ ligne.quantite|number_format(2, ',', ' ') }}</td>
                    <td style=\"padding: 2px !important; text-align: right; white-space: nowrap ; font-weight: bold\"
                        class=\"col-blue\">{{ ligne.pu|number_format(2, ',', ' ') }}</td>
                    <td style=\"padding: 2px !important; text-align: right; white-space: nowrap ; font-weight: bold\"
                        class=\"col-blue\">{{ (ligne.quantite  * ligne.pu)|number_format(2, ',', ' ') }}</td>
                </tr>

                {% for lign in ligne.article.composer.lignes %}
                    <tr>
                        <td style=\"padding: 0 10px !important; font-weight: bold\" class=\"col-pink\">
                            # {{ lign.designation|raw }}</td>
                        <td style=\"padding: 0 10px !important; text-align: right; font-weight: bold\"
                            class=\"col-pink\">{{ lign.unite }}</td>
                        <td style=\"padding: 0 10px !important; text-align: right; font-weight: bold; white-space: nowrap\"
                            class=\"col-pink\">{{ (lign.quantite*ligne.quantite)|number_format(2, ',', ' ') }}</td>
                        <td style=\"padding: 0 10px !important; text-align: right; font-weight: bold; white-space: nowrap\"
                            class=\"col-pink\">{{ lign.pu|number_format(2, ',', ' ') }}</td>
                        <td style=\"padding: 0 10px !important; text-align: right; font-weight: bold; white-space: nowrap\"
                            class=\"col-pink\">{{ (lign.quantite  * lign.pu * ligne.quantite)|number_format(2, ',', ' ') }}</td>
                    </tr>
                {% endfor %}

            {% endfor %}
        </table>
        <table class=\"table-striped table-bordered display nowrap\" style=\"width: 100%; margin-top: 30px\">
            <tr>
                <td colspan=\"5\" class=\"bolo700 col-blue text-left h5\">INVENTAIRE DES ARTICLES</td>
            </tr>
        </table>
        <table class=\"table-striped table-bordered display nowrap\"
               style=\"width: 100%\" id=\"dataINVE\">
            <thead>
            <tr class=\"text-center\">
                <th>ARTICLES</th>
                <th>ARTICLES COMMANDÉS</th>
                <th class=\"text-center\">PRÉVUE</th>
                <th class=\"text-center\">COMMANDÉE</th>
                <th class=\"text-center\">RESTE</th>
            </tr>
            </thead>
            <tbody>
            {% for ligne in invente %}
                {% if ligne.bon %}
                    {% if ligne.bon.etat == 'valide' %}
                        <tr>
                            <td style=\"padding: 2px !important;\">{{ ligne.designation|upper|striptags|raw }}</td>
                            <td><a
                                        href=\"{{ path('editbon', {'id': ligne.bon.id,  'idchantier': ligne.bon.chantier.id}) }}\"
                                        class=\"col-blue\">&raquo;
                                    BON
                                    N° {{ ligne.bon.numbon }}</a></td>
                            <td style=\"padding: 2px !important; text-align: right\">{{ ligne.pu|number_format(2, ',', ' ') }}</td>
                            <td style=\"padding: 2px !important; text-align: right\">{{ ligne.quantite }}</td>
                            <td style=\"padding: 2px !important; text-align: right\">{{ (ligne.quantite  * ligne.pu)|number_format(2, ',', ' ') }}</td>
                        </tr>
                    {% endif %}
                {% endif %}
            {% endfor %}
            </tbody>
        </table>
        <br><br> <br><br> <br><br> <br><br>
    </div>
{% endif %}

{# bon #}
{% if type == 'abon' %}
    <p style=\"clear: both\"></p>
    <div class=\"bood\">
        <div>
            <table style=\"margin-top:{{ formes.headerHeight }}cm; float: right;\">
                <tr>
                    <td style=\"border: none !important;text-align: center; \">
                        <b>{{ bon.client.nomclient|upper }}</b><br>
                        {% if bon.client.adresse  == \" \" %}
                            {{ bons.client.adresse }}
                        {% endif %}

                    </td>
                </tr>
            </table>
            <p style=\"clear: both\"></p>
            <table style=\"text-align: left\">
                <tr>
                    <td style=\"border: none !important; font-size: 25px\">
                        {% if bon.type == \"oui\" %}
                            <b>BON DE COMMANDE - FOURNISSEUR</b>
                        {% endif %}
                        {% if bon.type == \"non\" %}
                            <b>BON DE RETOUR DE COMMANDE - FOURNISSEUR</b>
                        {% endif %}
                        {% if bon.type == \"none\" %}
                            <b>BON DE LIVRAISON</b>
                        {% endif %}
                        {% if bon.type == \"pst\" %}
                            <b>BON DE COMMANDE - PRESTATAIRE</b>
                        {% endif %}
                        {% if bon.type == \"cps\" %}
                            <b>PRÉVISION ARTICLE COMPOSÉ</b>
                        {% endif %}
                        {% if bon.type == \"prepa\" %}
                            <b>BON DE SUIVI DE COMMANDE</b>
                        {% endif %}
                    </td>
                </tr>
            </table>
            <p style=\"clear: both\"></p>
            <table>
                <tr style=\"background-color: #f8f9fa !important; font-weight: 700\">
                    <td class=\"text-center\">DATE</td>
                    {% if bon.type == \"prepa\" %}
                        <td class=\"text-center\">N° DE BON DE SUIVI</td>
                    {% else %}
                        <td class=\"text-center\">N° DE BON</td>
                    {% endif %}

                    {% if bon.type == \"oui\" or bon.type == \"none\" %}
                        <td class=\"text-center\">N° DE BON DE SUIVI</td>
                    {% endif %}
                    <td class=\"text-center\">SELON DEVIS N°</td>

                    {% if bon.type == \"pst\" %}
                        <td class=\"text-center\">PRESTATAIRE</td>
                    {% endif %}

                    {% if bon.type == \"none\" or bon.type == \"oui\" %}
                        <td class=\"text-center\">FOURNISSEUR</td>
                    {% endif %}

                </tr>
                <tr>
                    <td class=\"text-center\">{{ bon.date|date('d/m/y') }}</td>
                    <td class=\"text-center\">{{ bon.numbon }}</td>
                    {% if bon.type == \"oui\" or bon.type == \"non\" %}
                        <td class=\"text-center\">{% if bon.preparation is not null %}{{ bon.preparation.numbon }}{% endif %}</td>
                    {% endif %}
                    <td class=\"text-center\">
                        {% if bon.devis is not null %}
                            {{ bon.devis.iddevis }}
                        {% endif %}
                    </td>

                    {% if bon.type != \"prepa\" %}
                        {% if bon.type != \"none\" or bon.type != \"cps\" %}
                            {% if bon.fournisseur is not null %}
                                <td class=\"text-center\">{{ bon.fournisseur.fournisseur|upper }}</td>
                            {% else %}
                                <td class=\"text-center\"></td>
                            {% endif %}
                        {% endif %}
                    {% endif %}

                </tr>
                <tr>
                    <td
                            {% if bon.type == \"none\" or bon.type == \"cps\" %} colspan=\"3\" {% endif %}
                            {% if bon.type == \"prepa\" or bon.type == \"pst\" %} colspan=\"4\" {% endif %}
                            {% if bon.type == \"oui\" or bon.type == \"non\" %} colspan=\"5\" {% endif %}
                    >
                        <span style=\"text-decoration: underline; font-weight: bold\">RÉFÉRENCE</span><br>{{ bon.bonreference|raw }}
                    </td>
                </tr>
            </table>
        </div>
        <br>
        <div>
            <table style=\"width: 100%;\">
                <tr class=\"printer\">
                    {% if bon.aaref == 'oui' %}
                        <th style=\"text-align: center\">RÉF</th>
                    {% endif %}
                    <th style=\"max-width:500px !important; min-width: 250px !important; text-align: left\">
                        DÉSIGNATION
                    </th>
                    <th style=\"text-align: center\">UNITÉ</th>

                    {% if bon.type == \"none\" %}
                        <th style=\"text-align: center\">QUANTITÉ LIVRÉE</th>
                    {% endif %}
                    {% if bon.type == \"prepa\" %}
                        <th style=\"text-align: center\">QTÉ<br>PRÉVUE</th>
                        <th style=\"text-align: center\">QTÉ<br>LIVRÉE</th>
                        <th style=\"text-align: center\">RESTE&nbsp;À <br>LIVRER</th>
                    {% endif %}
                    {% if bon.type == \"oui\" or bon.type == \"non\" %}
                        {% if bon.preparation is not null %}
                            <th style=\"text-align: center\">QTÉ<br>PRÉVUE</th>
                            <th style=\"text-align: center\">QTÉ<br>LIVRÉE</th>
                            <th style=\"text-align: center\">RESTE&nbsp;À <br>LIVRER</th>
                            <th style=\"text-align: center\"> QTÉ<br>DEMANDÉE</th>
                        {% else %}
                            <th style=\"text-align: center\"> QTÉ</th>
                        {% endif %}
                    {% endif %}
                    {% if bon.type == \"cps\" or bon.type == \"pst\" %}
                        <th style=\"text-align: center\"> QTÉ</th>
                    {% endif %}
                    <th style=\"text-align: center\">PRIX U.</th>
                    {% if bon.aarem == 'oui' %}
                        <th style=\" text-align: center\">REMISE</th>
                    {% endif %}
                    <th style=\"text-align: center\">MONTANT&nbsp;HT</th>

                </tr>


                {% for group in listGroup %}
                    <tr class=\"togo\">
                        {% if bon.aaref == 'oui' and bon.aarem == 'oui' %}
                            <td class=\"text-center\">{{ group.reference }}</td>
                            <td colspan=\"7\" style=\"font-weight: bold\">{{ group.groupe|striptags|raw }}</td>
                        {% endif %}
                        {% if bon.aaref == 'non' and bon.aarem == 'non' %}
                            <td colspan=\"5\" style=\"font-weight: bold\">{{ group.groupe|striptags|raw }}</td>
                        {% endif %}
                        {% if bon.aaref == 'oui' and bon.aarem == 'non' %}
                            <td class=\"text-center\">{{ group.reference }}</td>
                            <td colspan=\"6\" style=\"font-weight: bold\">{{ group.groupe|striptags|raw }}</td>
                        {% endif %}
                        {% if bon.aaref == 'non' and bon.aarem == 'oui' %}
                            <td colspan=\"6\" style=\"font-weight: bold\">{{ group.groupe|striptags|raw }}</td>
                        {% endif %}

                    </tr>

                    {% set st = 0 %}

                    {% for lign in group.lignes %}
                        <tr>
                            {% if bon.aaref == 'oui' %}
                                <td style=\"text-align: center\">{{ lign.reference }}</td>
                            {% endif %}
                            <td class=\"text-left\">{{ lign.designation|raw }}</td>
                            <td style=\"text-align: center\">{{ lign.unite }}</td>
                            <td style=\"text-align: center\">{{ lign.quantite|number_format(2, ',', ' ') }}<br><span
                                        class=\"hider\">{{ lign.quantite|number_format(5, '', '') }}</span></td>
                            {% if bon.type != \"none\" %}
                                <td style=\"text-align: right\">
                                    {{ lign.pu|number_format(2, ',', ' ') }}<br>
                                    <span class=\"hider\">{{ lign.pu|number_format(6, '', '') }}</span>
                                </td>
                                {% if bon.aarem == 'oui' %}
                                    <td style=\"text-align: center\">{{ lign.remise }}%</td>
                                {% endif %}
                                {% if bon.aarem == 'non' %}
                                    <td style=\"text-align: right\">{% set st = (lign.pu * lign.quantite) + st %} {{ (lign.pu * lign.quantite)|number_format(2, ',', ' ') }}</td>
                                {% else %}
                                    <td style=\"text-align: right\">{% set st = ((lign.pu * lign.quantite)*((100 - lign.remise)/100)) + st %}{{ ((lign.pu * lign.quantite)*((100 - lign.remise)/100))|number_format(2, ',', ' ') }}</td>
                                {% endif %}
                            {% endif %}
                            </td>
                        </tr>
                    {% endfor %}

                    <tr class=\"togo\">
                        {% if bon.aaref == 'oui' and bon.aarem == 'oui' %}
                            <td colspan=\"7\" style=\"text-align: right\">
                                <b>SOUS-TOTAL: {{ st|number_format(2, ',', ' ') }}</b>
                            </td>
                        {% endif %}
                        {% if bon.aaref == 'non' and bon.aarem == 'non' %}
                            <td colspan=\"5\" style=\"text-align: right\">
                                <b>SOUS-TOTAL: {{ st|number_format(2, ',', ' ') }}</b>
                            </td>
                        {% endif %}
                        {% if bon.aaref == 'oui' and bon.aarem == 'non' %}
                            <td colspan=\"6\" style=\"text-align: right\">
                                <b>SOUS-TOTAL: {{ st|number_format(2, ',', ' ') }}</b>
                            </td>
                        {% endif %}
                        {% if bon.aaref == 'non' and bon.aarem == 'oui' %}
                            <td colspan=\"6\" style=\"text-align: right\">
                                <b>SOUS-TOTAL: {{ st|number_format(2, ',', ' ') }}</b>
                            </td>
                        {% endif %}

                    </tr>

                {% endfor %}

                {% for lign in lignes %}
                    {% if lign.groupe == null %}
                        <tr>
                            {% if bon.aaref == 'oui' %}
                                <td style=\"text-align: center\">{{ lign.reference }}</td>
                            {% endif %}
                            <td>{{ lign.designation|raw }}</td>
                            <td style=\"text-align: center\">{{ lign.unite }}</td>

                            {% if bon.type == \"prepa\" %}
                                <td style=\"text-align: center\">{{ lign.quantite|number_format(2, ',', ' ') }}
                                    <br><span
                                            class=\"hider\">{{ lign.quantite|number_format(5, '', '') }}</span></td>

                                <td style=\"text-align: center\">{{ lign.livrer|number_format(2, ',', ' ') }}
                                    <br><span
                                            class=\"hider\">{{ lign.livrer|number_format(5, '', '') }}</span></td>

                                <td style=\"text-align: center\">{{ lign.reste|number_format(2, ',', ' ') }}<br><span
                                            class=\"hider\">{{ lign.reste|number_format(5, '', '') }}</span></td>
                            {% endif %}
                            {% if bon.type == \"oui\" or bon.type == \"non\" %}
                                {% if bon.preparation is not null %}
                                    <td style=\"text-align: center\">{{ (lign.livrer + lign.reste)|number_format(2, ',', ' ') }}
                                        <br><span
                                                class=\"hider\">{{ (lign.livrer + lign.reste)|number_format(5, '', '') }}</span>
                                    </td>
                                    <td style=\"text-align: center\">{{ lign.livrer|number_format(2, ',', ' ') }}
                                        <br><span
                                                class=\"hider\">{{ lign.livrer|number_format(5, '', '') }}</span></td>
                                    <td style=\"text-align: center\">{{ lign.reste|number_format(2, ',', ' ') }}<br><span
                                                class=\"hider\">{{ lign.reste|number_format(5, '', '') }}</span></td>
                                    <td style=\"text-align: center\">{{ lign.quantite|number_format(2, ',', ' ') }}
                                        <br><span
                                                class=\"hider\">{{ lign.quantite|number_format(5, '', '') }}</span></td>
                                {% else %}
                                    <td style=\"text-align: center\">{{ lign.quantite|number_format(2, ',', ' ') }}
                                        <br><span
                                                class=\"hider\">{{ lign.quantite|number_format(5, '', '') }}</span></td>
                                {% endif %}
                            {% endif %}
                            {% if bon.type == \"cps\" or bon.type == \"pst\" %}
                                <td style=\"text-align: center\">{{ lign.quantite|number_format(2, ',', ' ') }}
                                    <br><span
                                            class=\"hider\">{{ lign.quantite|number_format(5, '', '') }}</span></td>
                            {% endif %}
                            {% if bon.type is not same as \"none\" %}
                                <td style=\"text-align: right\">{{ lign.pu|number_format(2, ',', ' ') }}<br><span
                                            class=\"hider\">{{ lign.pu|number_format(6, '', '') }}</span></td>
                                {% if bon.aarem == 'oui' %}
                                    <td style=\"text-align: center\">{{ lign.remise }}%</td>
                                {% endif %}
                                {% if bon.aarem == 'non' %}
                                    <td style=\"text-align: right\">{{ (lign.pu * lign.quantite)|number_format(2, ',', ' ') }}</td>
                                {% endif %}
                                {% if bon.aarem != 'non' %}
                                    <td style=\"text-align: right\">{{ ((lign.pu * lign.quantite)*((100 - lign.remise)/100))|number_format(2, ',', ' ') }}</td>
                                {% endif %}
                            {% endif %}
                        </tr>
                    {% endif %}
                {% endfor %}

                {% if bon.type != \"none\" and bon.type != \"cps\" %}
                    {% if bon.type != \"pst\" %}
                        {% if bon.caisses is not null %}
                            {% if bon.aaref is same as 'oui' %}
                                {% if bon.aarem is same as 'oui' %}
                                    <tr>
                                        <td colSpan=\"10\" class=\"borde\" style=\"color: red\"><b>HISTORIQUE DES
                                                PAIEMENTS</b>
                                        </td>
                                    </tr>
                                    {% set recu = 0 %}
                                    {% for caisse in bon.caisses %}
                                        {% if caisse.etat == 'valide' %}
                                            <tr>
                                                <td colSpan=\"9\">{{ caisse.date|date('d/m/y') }} |
                                                    <span>N° Bon: {{ caisse.numcaisse }}</span> |
                                                    Somme reçue
                                                </td>
                                                <td>
                                                    {{ caisse.montant|number_format(2, ',', ' ') }}
                                                    {% set recu = caisse.montant + recu %}
                                                </td>
                                            </tr>
                                        {% endif %}
                                    {% endfor %}
                                {% endif %}
                                {% if bon.aarem is not same as 'oui' %}
                                    <tr>
                                        <td colSpan=\"9\" class=\"borde\" style=\"color: red\"><b>HISTORIQUE DES PAIEMENTS</b>
                                        </td>
                                    </tr>
                                    {% set recu = 0 %}
                                    {% for caisse in bon.caisses %}
                                        {% if caisse.etat == 'valide' %}
                                            <tr>
                                                <td colSpan=\"5\">{{ caisse.date|date('d/m/y') }} |
                                                    <span>N° Bon: {{ caisse.numcaisse }}</span> |
                                                    Somme reçue
                                                </td>
                                                <td>
                                                    {{ caisse.montant|number_format(2, ',', ' ') }}
                                                    {% set recu = caisse.montant + recu %}
                                                </td>
                                            </tr>
                                        {% endif %}
                                    {% endfor %}
                                {% endif %}
                            {% endif %}
                            {% if bon.aaref is not same as 'oui' %}
                                {% if bon.aarem is same as 'oui' %}
                                    <tr>
                                        <td colSpan=\"9\" class=\"borde\" style=\"color: red\"><b>HISTORIQUE DES PAIEMENTS</b>
                                        </td>
                                    </tr>
                                    {% set recu = 0 %}
                                    {% for caisse in bon.caisses %}
                                        {% if caisse.etat == 'valide' %}
                                            <tr>
                                                <td colSpan=\"6\">{{ caisse.date|date('d/m/y') }} |
                                                    <span>N° Bon: {{ caisse.numcaisse }}</span> |
                                                    Somme reçue
                                                </td>
                                                <td>
                                                    {{ caisse.montant|number_format(2, ',', ' ') }}
                                                    {% set recu = caisse.montant + recu %}
                                                </td>
                                            </tr>
                                        {% endif %}
                                    {% endfor %}
                                {% endif %}
                                {% if bon.aarem != 'oui' %}
                                    <tr>
                                        <td colSpan=\"8\" class=\"borde\" style=\"color: red\"><b>HISTORIQUE DES PAIEMENTS</b>
                                        </td>
                                    </tr>
                                    {% set recu = 0 %}
                                    {% for caisse in bon.caisses %}
                                        {% if caisse.etat == 'valide' %}
                                            <tr>
                                                <td colSpan=\"4\">{{ caisse.date|date('d/m/y') }} |
                                                    <span>N° Bon: {{ caisse.numcaisse }}</span> |
                                                    Somme reçue
                                                </td>
                                                <td>
                                                    {{ caisse.montant|number_format(2, ',', ' ') }}
                                                    {% set recu = caisse.montant + recu %}
                                                </td>
                                            </tr>
                                        {% endif %}
                                    {% endfor %}
                                {% endif %}
                            {% endif %}
                        {% endif %}
                    {% endif %}
                {% endif %}

            </table>
            <p style=\"clear: both\"></p>
            {% if bon.type is not same as \"pst\" and bon.type is not same as 'none' %}
                {% if bon.type is not same as \"prepa\" %}
                    <table class=\"table-bordered\" style=\"float: right; width: 60% ; margin-top: 10px\">
                        <tr style=\"font-weight: 600\">
                            <td style=\"text-align: center ; background-color: #f8f9fa\"><b>SOMME PERÇUE</b></td>
                            <td style=\"text-align: center ; background-color: #f8f9fa\"><b>RESTE À PAYER</b></td>
                        </tr>
                        <tr>
                            <td style=\"text-align: center\">{{ bon.recu|number_format(2, ',', ' ') }}</td>
                            <td style=\"text-align: center\">{{ bon.reste|number_format(2, ',', ' ') }}</td>
                        </tr>
                    </table>
                {% endif %}
                <table class=\"table-bordered\" style=\"float: right; width: 60% ; margin-top: 10px\">
                    <tr style=\"font-weight: 600\">
                        <td style=\"text-align: center ; background-color: #f8f9fa\"><b>TOTAL
                                HT</b></td>
                        {% if bon.aarem == 'oui' and  bon.type != \"none\" %}
                            <td style=\"text-align: center ; background-color: #f8f9fa\">
                                <b>REMISE</b></td>
                        {% endif %}
                        <td style=\"text-align: center ; background-color: #f8f9fa\">
                            <b>TVA {{ bon.tva }}%</b></td>
                        <td style=\"text-align: center ; background-color: #f8f9fa\"><b>NET À
                                PAYER</b></td>
                    </tr>
                    <tr>
                        <td style=\"text-align: center\">{{ bon.totalht|number_format(2, ',', ' ') }}</td>
                        {% if bon.aarem == 'oui' and  bon.type != \"none\" %}
                            <td style=\"text-align: center\">{{ bon.vremise|number_format(2, ',', ' ') }}</td>
                        {% endif %}
                        <td style=\"text-align: center\">{{ bon.vtva|number_format(2, ',', ' ') }}</td>
                        <td style=\"text-align: center\">{{ bon.totalttc|number_format(2, ',', ' ') }}</td>
                    </tr>
                </table>
            {% endif %}
            {% if bon.type == \"pst\" %}
                {% if bon.type == \"none\" %}
                    <table class=\"table-bordered\" style=\"float: left; width: 60% ; margin-top: 10px\">
                        <tr style=\"font-weight: 600\">
                            <td style=\"text-align: center ; background-color: #f8f9fa\"><b>TOTAL
                                    HT</b></td>
                            {% if bon.aarem == 'oui' and  bon.type != \"none\" %}
                                <td style=\"text-align: center ; background-color: #f8f9fa\">
                                    <b>REMISE</b></td>
                            {% endif %}
                            <td style=\"text-align: center ; background-color: #f8f9fa\">
                                <b>TVA {{ bon.tva }}%</b></td>
                            <td style=\"text-align: center ; background-color: #f8f9fa\"><b>NET À
                                    PAYER</b></td>
                        </tr>
                        <tr>
                            <td style=\"text-align: center\">{{ bon.totalht|number_format(2, ',', ' ') }}</td>
                            {% if bon.aarem == 'oui' and  bon.type != \"none\" %}
                                <td style=\"text-align: center\">{{ bon.vremise|number_format(2, ',', ' ') }}</td>
                            {% endif %}
                            <td style=\"text-align: center\">{{ bon.vtva|number_format(2, ',', ' ') }}</td>
                            <td style=\"text-align: center\">{{ bon.totalttc|number_format(2, ',', ' ') }}</td>
                        </tr>
                    </table>
                {% endif %}
                <table class=\"table-bordered\" style=\"float: left; width: 60% ; margin-top: 10px\">
                    <tr style=\"font-weight: 600\">
                        <td style=\"text-align: center ; background-color: #f8f9fa\"><b>TOTAL
                                HT</b></td>
                        {% if bon.aarem == 'oui' and  bon.type != \"none\" %}
                            <td style=\"text-align: center ; background-color: #f8f9fa\">
                                <b>REMISE</b></td>
                        {% endif %}
                        <td style=\"text-align: center ; background-color: #f8f9fa\">
                            <b>TVA {{ bon.tva }}%</b></td>
                        <td style=\"text-align: center ; background-color: #f8f9fa\"><b>NET À
                                PAYER</b></td>
                    </tr>
                    <tr>
                        <td style=\"text-align: center\">{{ bon.totalht|number_format(2, ',', ' ') }}</td>
                        {% if bon.aarem == 'oui' and  bon.type != \"none\" %}
                            <td style=\"text-align: center\">{{ bon.vremise|number_format(2, ',', ' ') }}</td>
                        {% endif %}
                        <td style=\"text-align: center\">{{ bon.vtva|number_format(2, ',', ' ') }}</td>
                        <td style=\"text-align: center\">{{ bon.totalttc|number_format(2, ',', ' ') }}</td>
                    </tr>
                </table>
                <table class=\"table-bordered\" style=\"float: right; width: 38% ; margin-top: 10px\">
                    <tr style=\"font-weight: 600\">
                        <td style=\"text-align: center ;  background-color: #f8f9fa; font-weight: 700\">SOMME
                            RECUE
                        </td>
                        <td style=\"text-align: center ; background-color: #f8f9fa; font-weight: 700\">RESTE À
                            PAYER
                        </td>
                    </tr>
                    <tr>
                        <td style=\"text-align: center\">{{ bon.recu|number_format(2, ',', ' ') }}</td>
                        <td style=\"text-align: center\">{{ bon.reste|number_format(2, ',', ' ') }}</td>
                    </tr>
                </table>
            {% endif %}
            {% if bon.type == \"none\" %}
                <table style=\"width: 100%; margin-Top: 5px;\">
                    <tr>
                        <td style=\"text-align: left ; text-decoration: underline; border: none !important;\">VISA
                            CHEF CHANTIER
                        </td>
                        <td style=\"text-align: center ; text-decoration: underline; border: none !important;\">VISA
                            CHEF DÉPÔT
                        </td>
                        <td style=\"text-align: right ; text-decoration: underline; border: none !important;\">VISA
                            DIRECTION
                        </td>
                    </tr>
                </table>
            {% endif %}

            <p style=\"clear: both\"></p>
            <br><br>
            {% if bon.type != \"none\" %}
                <p style=\"font-weight: 700; color: #111010; text-align: left\">
                    Arrêté le présent bon à la somme de: <br><span
                            style=\"color: dimgray\"> {{ bon.totalttc|craue_spellout() }} {{ bon.monnaie.code }}</span>
                </p><br>
                <p style=\"float: right\"><u>SIGNATURE AUTORISÉE</u></p><br><br><br>
            {% endif %}
            {% if bon.conditions is not null %}
                <p style=\"float: left; color: #4e73df;\"><u>INFORMATIONS ADDITIONNELLES</u></p>
                <p style=\"clear: both\"></p>
                <p style=\"color: #000000;\">{{ bon.conditions|raw }}</p>
            {% endif %}

        </div>
    </div>
{% endif %}

{# bon #}
{% if type == 'bon' %}
    <div class=\"bood\">
        <div>
            <table style=\"margin-top: {{ formes.teteDB }}px !important; float: right\">
                <tr>
                    <td style=\"border: none !important; text-align: center\">
                        <b>{{ bon.client.nomclient|upper }}</b> <br>
                        {{ bon.client.adresse }} <br>
                    </td>
                </tr>
            </table>
            <p style=\"clear: both\"></p>
            <br>
            <table style=\"text-align: left\">
                <tr>
                    <td style=\"border: none !important; font-size: 25px\">
                        {% if bon.type == \"oui\" %}
                            <b>BON DE COMMANDE - FOURNISSEUR</b>
                        {% endif %}
                        {% if bon.type == \"non\" %}
                            <b>BON DE RETOUR DE COMMANDE - FOURNISSEUR</b>
                        {% endif %}
                        {% if bon.type == \"none\" %}
                            <b>BON DE LIVRAISON</b>
                        {% endif %}
                        {% if bon.type == \"pst\" %}
                            <b>BON DE COMMANDE - PRESTATAIRE</b>
                        {% endif %}
                        {% if bon.type == \"cps\" %}
                            <b>PRÉVISION ARTICLE COMPOSÉ</b>
                        {% endif %}
                        {% if bon.type == \"prepa\" %}
                            <b>BON DE SUIVI DE COMMANDE</b>
                        {% endif %}
                    </td>
                </tr>
            </table>
            <p style=\"clear: both\"></p>
            <table>
                <tr style=\"background-color: #f8f9fa !important; font-weight: 700\">
                    <td class=\"text-center\">DATE</td>
                    {% if bon.type == \"prepa\" %}
                        <td class=\"text-center\">N° DE BON DE SUIVI</td>
                    {% else %}
                        <td class=\"text-center\">N° DE BON</td>
                    {% endif %}

                    {% if bon.type == \"oui\" or bon.type == \"none\" %}
                        <td class=\"text-center\">N° DE BON DE SUIVI</td>
                    {% endif %}
                    <td class=\"text-center\">SELON DEVIS N°</td>

                    {% if bon.type == \"pst\" %}
                        <td class=\"text-center\">PRESTATAIRE</td>
                    {% endif %}

                    {% if bon.type == \"none\" or bon.type == \"oui\" %}
                        <td class=\"text-center\">FOURNISSEUR</td>
                    {% endif %}

                </tr>
                <tr>
                    <td class=\"text-center\">{{ bon.date|date('d/m/y') }}</td>
                    <td class=\"text-center\">{{ bon.numbon }}</td>
                    {% if bon.type == \"oui\" or bon.type == \"non\" %}
                        <td class=\"text-center\">{% if bon.preparation is not null %}{{ bon.preparation.numbon }}{% endif %}</td>
                    {% endif %}
                    <td class=\"text-center\">
                        {% if bon.devis is not null %}
                            {{ bon.devis.iddevis }}
                        {% endif %}
                    </td>

                    {% if bon.type != \"prepa\" %}
                        {% if bon.type != \"none\" or bon.type != \"cps\" %}
                            {% if bon.fournisseur is not null %}
                                <td class=\"text-center\">{{ bon.fournisseur.fournisseur|upper }}</td>
                            {% else %}
                                <td class=\"text-center\"></td>
                            {% endif %}
                        {% endif %}
                    {% endif %}

                </tr>
                <tr>
                    <td
                            {% if bon.type == \"none\" or bon.type == \"cps\" %} colspan=\"3\" {% endif %}
                            {% if bon.type == \"prepa\" or bon.type == \"pst\" %} colspan=\"4\" {% endif %}
                            {% if bon.type == \"oui\" or bon.type == \"non\" %} colspan=\"5\" {% endif %}
                    >
                        <span style=\"text-decoration: underline; font-weight: bold\">RÉFÉRENCE</span><br>{{ bon.bonreference|raw }}
                    </td>
                </tr>
            </table>
        </div>
        <br>
        <div>
            <table style=\"width: 100%;\">
                <tr class=\"printer\">
                    {% if bon.aaref == 'oui' %}
                        <th style=\"text-align: center\">RÉF</th>
                    {% endif %}
                    <th style=\"max-width:500px !important; min-width: 250px !important; text-align: left\">
                        DÉSIGNATION
                    </th>
                    <th style=\"text-align: center\">UNITÉ</th>

                    {% if bon.type == \"none\" %}
                        <th style=\"text-align: center\">QUANTITÉ LIVRÉE</th>
                    {% endif %}
                    {% if bon.type == \"prepa\" %}
                        <th style=\"text-align: center\">QTÉ<br>PRÉVUE</th>
                        <th style=\"text-align: center\">QTÉ<br>LIVRÉE</th>
                        <th style=\"text-align: center\">RESTE&nbsp;À <br>LIVRER</th>
                    {% endif %}
                    {% if bon.type == \"oui\" or bon.type == \"non\" %}
                        {% if bon.preparation is not null %}
                            <th style=\"text-align: center\">QTÉ<br>PRÉVUE</th>
                            <th style=\"text-align: center\">QTÉ<br>LIVRÉE</th>
                            <th style=\"text-align: center\">RESTE&nbsp;À <br>LIVRER</th>
                            <th style=\"text-align: center\"> QTÉ<br>DEMANDÉE</th>
                        {% else %}
                            <th style=\"text-align: center\"> QTÉ</th>
                        {% endif %}
                    {% endif %}
                    {% if bon.type == \"cps\" or bon.type == \"pst\" %}
                        <th style=\"text-align: center\"> QTÉ</th>
                    {% endif %}
                    <th style=\"text-align: center\">PRIX U.</th>
                    {% if bon.aarem == 'oui' %}
                        <th style=\" text-align: center\">REMISE</th>
                    {% endif %}
                    <th style=\"text-align: center\">MONTANT&nbsp;HT</th>

                </tr>


                {% for group in listGroup %}
                    <tr class=\"togo\">
                        {% if bon.aaref == 'oui' and bon.aarem == 'oui' %}
                            <td class=\"text-center\">{{ group.reference }}</td>
                            <td colspan=\"7\" style=\"font-weight: bold\">{{ group.groupe|striptags|raw }}</td>
                        {% endif %}
                        {% if bon.aaref == 'non' and bon.aarem == 'non' %}
                            <td colspan=\"5\" style=\"font-weight: bold\">{{ group.groupe|striptags|raw }}</td>
                        {% endif %}
                        {% if bon.aaref == 'oui' and bon.aarem == 'non' %}
                            <td class=\"text-center\">{{ group.reference }}</td>
                            <td colspan=\"6\" style=\"font-weight: bold\">{{ group.groupe|striptags|raw }}</td>
                        {% endif %}
                        {% if bon.aaref == 'non' and bon.aarem == 'oui' %}
                            <td colspan=\"6\" style=\"font-weight: bold\">{{ group.groupe|striptags|raw }}</td>
                        {% endif %}

                    </tr>

                    {% set st = 0 %}

                    {% for lign in group.lignes %}
                        <tr>
                            {% if bon.aaref == 'oui' %}
                                <td style=\"text-align: center\">{{ lign.reference }}</td>
                            {% endif %}
                            <td class=\"text-left\">{{ lign.designation|raw }}</td>
                            <td style=\"text-align: center\">{{ lign.unite }}</td>
                            <td style=\"text-align: center\">{{ lign.quantite|number_format(2, ',', ' ') }}<br><span
                                        class=\"hider\">{{ lign.quantite|number_format(5, '', '') }}</span></td>
                            {% if bon.type != \"none\" %}
                                <td style=\"text-align: right\">
                                    {{ lign.pu|number_format(2, ',', ' ') }}<br>
                                    <span class=\"hider\">{{ lign.pu|number_format(6, '', '') }}</span>
                                </td>
                                {% if bon.aarem == 'oui' %}
                                    <td style=\"text-align: center\">{{ lign.remise }}%</td>
                                {% endif %}
                                {% if bon.aarem == 'non' %}
                                    <td style=\"text-align: right\">{% set st = (lign.pu * lign.quantite) + st %} {{ (lign.pu * lign.quantite)|number_format(2, ',', ' ') }}</td>
                                {% else %}
                                    <td style=\"text-align: right\">{% set st = ((lign.pu * lign.quantite)*((100 - lign.remise)/100)) + st %}{{ ((lign.pu * lign.quantite)*((100 - lign.remise)/100))|number_format(2, ',', ' ') }}</td>
                                {% endif %}
                            {% endif %}
                            </td>
                        </tr>
                    {% endfor %}

                    <tr class=\"togo\">
                        {% if bon.aaref == 'oui' and bon.aarem == 'oui' %}
                            <td colspan=\"7\" style=\"text-align: right\">
                                <b>SOUS-TOTAL: {{ st|number_format(2, ',', ' ') }}</b>
                            </td>
                        {% endif %}
                        {% if bon.aaref == 'non' and bon.aarem == 'non' %}
                            <td colspan=\"5\" style=\"text-align: right\">
                                <b>SOUS-TOTAL: {{ st|number_format(2, ',', ' ') }}</b>
                            </td>
                        {% endif %}
                        {% if bon.aaref == 'oui' and bon.aarem == 'non' %}
                            <td colspan=\"6\" style=\"text-align: right\">
                                <b>SOUS-TOTAL: {{ st|number_format(2, ',', ' ') }}</b>
                            </td>
                        {% endif %}
                        {% if bon.aaref == 'non' and bon.aarem == 'oui' %}
                            <td colspan=\"6\" style=\"text-align: right\">
                                <b>SOUS-TOTAL: {{ st|number_format(2, ',', ' ') }}</b>
                            </td>
                        {% endif %}

                    </tr>

                {% endfor %}

                {% for lign in lignes %}
                    {% if lign.groupe == null %}
                        <tr>
                            {% if bon.aaref == 'oui' %}
                                <td style=\"text-align: center\">{{ lign.reference }}</td>
                            {% endif %}
                            <td>{{ lign.designation|raw }}</td>
                            <td style=\"text-align: center\">{{ lign.unite }}</td>

                            {% if bon.type == \"prepa\" %}
                                <td style=\"text-align: center\">{{ lign.quantite|number_format(2, ',', ' ') }}
                                    <br><span
                                            class=\"hider\">{{ lign.quantite|number_format(5, '', '') }}</span></td>

                                <td style=\"text-align: center\">{{ lign.livrer|number_format(2, ',', ' ') }}
                                    <br><span
                                            class=\"hider\">{{ lign.livrer|number_format(5, '', '') }}</span></td>

                                <td style=\"text-align: center\">{{ lign.reste|number_format(2, ',', ' ') }}<br><span
                                            class=\"hider\">{{ lign.reste|number_format(5, '', '') }}</span></td>
                            {% endif %}
                            {% if bon.type == \"oui\" or bon.type == \"non\" %}
                                {% if bon.preparation is not null %}
                                    <td style=\"text-align: center\">{{ (lign.livrer + lign.reste)|number_format(2, ',', ' ') }}
                                        <br><span
                                                class=\"hider\">{{ (lign.livrer + lign.reste)|number_format(5, '', '') }}</span>
                                    </td>
                                    <td style=\"text-align: center\">{{ lign.livrer|number_format(2, ',', ' ') }}
                                        <br><span
                                                class=\"hider\">{{ lign.livrer|number_format(5, '', '') }}</span></td>
                                    <td style=\"text-align: center\">{{ lign.reste|number_format(2, ',', ' ') }}<br><span
                                                class=\"hider\">{{ lign.reste|number_format(5, '', '') }}</span></td>
                                    <td style=\"text-align: center\">{{ lign.quantite|number_format(2, ',', ' ') }}
                                        <br><span
                                                class=\"hider\">{{ lign.quantite|number_format(5, '', '') }}</span></td>
                                {% else %}
                                    <td style=\"text-align: center\">{{ lign.quantite|number_format(2, ',', ' ') }}
                                        <br><span
                                                class=\"hider\">{{ lign.quantite|number_format(5, '', '') }}</span></td>
                                {% endif %}
                            {% endif %}
                            {% if bon.type == \"cps\" or bon.type == \"pst\" %}
                                <td style=\"text-align: center\">{{ lign.quantite|number_format(2, ',', ' ') }}
                                    <br><span
                                            class=\"hider\">{{ lign.quantite|number_format(5, '', '') }}</span></td>
                            {% endif %}
                            {% if bon.type is not same as \"none\" %}
                                <td style=\"text-align: right\">{{ lign.pu|number_format(2, ',', ' ') }}<br><span
                                            class=\"hider\">{{ lign.pu|number_format(6, '', '') }}</span></td>
                                {% if bon.aarem == 'oui' %}
                                    <td style=\"text-align: center\">{{ lign.remise }}%</td>
                                {% endif %}
                                {% if bon.aarem == 'non' %}
                                    <td style=\"text-align: right\">{{ (lign.pu * lign.quantite)|number_format(2, ',', ' ') }}</td>
                                {% endif %}
                                {% if bon.aarem != 'non' %}
                                    <td style=\"text-align: right\">{{ ((lign.pu * lign.quantite)*((100 - lign.remise)/100))|number_format(2, ',', ' ') }}</td>
                                {% endif %}
                            {% endif %}
                        </tr>
                    {% endif %}
                {% endfor %}

                {% if bon.type != \"none\" and bon.type != \"cps\" %}
                    {% if bon.type != \"pst\" %}
                        {% if bon.caisses is not null %}
                            {% if bon.aaref is same as 'oui' %}
                                {% if bon.aarem is same as 'oui' %}
                                    <tr>
                                        <td colSpan=\"10\" class=\"borde\" style=\"color: red\"><b>HISTORIQUE DES
                                                PAIEMENTS</b>
                                        </td>
                                    </tr>
                                    {% set recu = 0 %}
                                    {% for caisse in bon.caisses %}
                                        {% if caisse.etat == 'valide' %}
                                            <tr>
                                                <td colSpan=\"9\">{{ caisse.date|date('d/m/y') }} |
                                                    <span>N° Bon: {{ caisse.numcaisse }}</span> |
                                                    Somme reçue
                                                </td>
                                                <td>
                                                    {{ caisse.montant|number_format(2, ',', ' ') }}
                                                    {% set recu = caisse.montant + recu %}
                                                </td>
                                            </tr>
                                        {% endif %}
                                    {% endfor %}
                                {% endif %}
                                {% if bon.aarem is not same as 'oui' %}
                                    <tr>
                                        <td colSpan=\"9\" class=\"borde\" style=\"color: red\"><b>HISTORIQUE DES PAIEMENTS</b>
                                        </td>
                                    </tr>
                                    {% set recu = 0 %}
                                    {% for caisse in bon.caisses %}
                                        {% if caisse.etat == 'valide' %}
                                            <tr>
                                                <td colSpan=\"5\">{{ caisse.date|date('d/m/y') }} |
                                                    <span>N° Bon: {{ caisse.numcaisse }}</span> |
                                                    Somme reçue
                                                </td>
                                                <td>
                                                    {{ caisse.montant|number_format(2, ',', ' ') }}
                                                    {% set recu = caisse.montant + recu %}
                                                </td>
                                            </tr>
                                        {% endif %}
                                    {% endfor %}
                                {% endif %}
                            {% endif %}
                            {% if bon.aaref is not same as 'oui' %}
                                {% if bon.aarem is same as 'oui' %}
                                    <tr>
                                        <td colSpan=\"9\" class=\"borde\" style=\"color: red\"><b>HISTORIQUE DES PAIEMENTS</b>
                                        </td>
                                    </tr>
                                    {% set recu = 0 %}
                                    {% for caisse in bon.caisses %}
                                        {% if caisse.etat == 'valide' %}
                                            <tr>
                                                <td colSpan=\"6\">{{ caisse.date|date('d/m/y') }} |
                                                    <span>N° Bon: {{ caisse.numcaisse }}</span> |
                                                    Somme reçue
                                                </td>
                                                <td>
                                                    {{ caisse.montant|number_format(2, ',', ' ') }}
                                                    {% set recu = caisse.montant + recu %}
                                                </td>
                                            </tr>
                                        {% endif %}
                                    {% endfor %}
                                {% endif %}
                                {% if bon.aarem != 'oui' %}
                                    <tr>
                                        <td colSpan=\"8\" class=\"borde\" style=\"color: red\"><b>HISTORIQUE DES PAIEMENTS</b>
                                        </td>
                                    </tr>
                                    {% set recu = 0 %}
                                    {% for caisse in bon.caisses %}
                                        {% if caisse.etat == 'valide' %}
                                            <tr>
                                                <td colSpan=\"4\">{{ caisse.date|date('d/m/y') }} |
                                                    <span>N° Bon: {{ caisse.numcaisse }}</span> |
                                                    Somme reçue
                                                </td>
                                                <td>
                                                    {{ caisse.montant|number_format(2, ',', ' ') }}
                                                    {% set recu = caisse.montant + recu %}
                                                </td>
                                            </tr>
                                        {% endif %}
                                    {% endfor %}
                                {% endif %}
                            {% endif %}
                        {% endif %}
                    {% endif %}
                {% endif %}

            </table>
            <p style=\"clear: both\"></p>
            {% if bon.type is not same as \"pst\" and bon.type is not same as 'none' %}
                {% if bon.type is not same as \"prepa\" %}
                <table class=\"table-bordered\" style=\"float: right; width: 60% ; margin-top: 10px\">
                    <tr style=\"font-weight: 600\">
                        <td style=\"text-align: center ; background-color: #f8f9fa\"><b>SOMME PERÇUE</b></td>
                        <td style=\"text-align: center ; background-color: #f8f9fa\"><b>RESTE À PAYER</b></td>
                    </tr>
                    <tr>
                        <td style=\"text-align: center\">{{ bon.recu|number_format(2, ',', ' ') }}</td>
                        <td style=\"text-align: center\">{{ bon.reste|number_format(2, ',', ' ') }}</td>
                    </tr>
                </table>
                {% endif %}
                <table class=\"table-bordered\" style=\"float: right; width: 60% ; margin-top: 10px\">
                    <tr style=\"font-weight: 600\">
                        <td style=\"text-align: center ; background-color: #f8f9fa\"><b>TOTAL
                                HT</b></td>
                        {% if bon.aarem == 'oui' and  bon.type != \"none\" %}
                            <td style=\"text-align: center ; background-color: #f8f9fa\">
                                <b>REMISE</b></td>
                        {% endif %}
                        <td style=\"text-align: center ; background-color: #f8f9fa\">
                            <b>TVA {{ bon.tva }}%</b></td>
                        <td style=\"text-align: center ; background-color: #f8f9fa\"><b>NET À
                                PAYER</b></td>
                    </tr>
                    <tr>
                        <td style=\"text-align: center\">{{ bon.totalht|number_format(2, ',', ' ') }}</td>
                        {% if bon.aarem == 'oui' and  bon.type != \"none\" %}
                            <td style=\"text-align: center\">{{ bon.vremise|number_format(2, ',', ' ') }}</td>
                        {% endif %}
                        <td style=\"text-align: center\">{{ bon.vtva|number_format(2, ',', ' ') }}</td>
                        <td style=\"text-align: center\">{{ bon.totalttc|number_format(2, ',', ' ') }}</td>
                    </tr>
                </table>
            {% endif %}
            {% if bon.type == \"pst\" %}
                {% if bon.type == \"none\" %}
                    <table class=\"table-bordered\" style=\"float: left; width: 60% ; margin-top: 10px\">
                        <tr style=\"font-weight: 600\">
                            <td style=\"text-align: center ; background-color: #f8f9fa\"><b>TOTAL
                                    HT</b></td>
                            {% if bon.aarem == 'oui' and  bon.type != \"none\" %}
                                <td style=\"text-align: center ; background-color: #f8f9fa\">
                                    <b>REMISE</b></td>
                            {% endif %}
                            <td style=\"text-align: center ; background-color: #f8f9fa\">
                                <b>TVA {{ bon.tva }}%</b></td>
                            <td style=\"text-align: center ; background-color: #f8f9fa\"><b>NET À
                                    PAYER</b></td>
                        </tr>
                        <tr>
                            <td style=\"text-align: center\">{{ bon.totalht|number_format(2, ',', ' ') }}</td>
                            {% if bon.aarem == 'oui' and  bon.type != \"none\" %}
                                <td style=\"text-align: center\">{{ bon.vremise|number_format(2, ',', ' ') }}</td>
                            {% endif %}
                            <td style=\"text-align: center\">{{ bon.vtva|number_format(2, ',', ' ') }}</td>
                            <td style=\"text-align: center\">{{ bon.totalttc|number_format(2, ',', ' ') }}</td>
                        </tr>
                    </table>
                {% endif %}
                <table class=\"table-bordered\" style=\"float: left; width: 60% ; margin-top: 10px\">
                    <tr style=\"font-weight: 600\">
                        <td style=\"text-align: center ; background-color: #f8f9fa\"><b>TOTAL
                                HT</b></td>
                        {% if bon.aarem == 'oui' and  bon.type != \"none\" %}
                            <td style=\"text-align: center ; background-color: #f8f9fa\">
                                <b>REMISE</b></td>
                        {% endif %}
                        <td style=\"text-align: center ; background-color: #f8f9fa\">
                            <b>TVA {{ bon.tva }}%</b></td>
                        <td style=\"text-align: center ; background-color: #f8f9fa\"><b>NET À
                                PAYER</b></td>
                    </tr>
                    <tr>
                        <td style=\"text-align: center\">{{ bon.totalht|number_format(2, ',', ' ') }}</td>
                        {% if bon.aarem == 'oui' and  bon.type != \"none\" %}
                            <td style=\"text-align: center\">{{ bon.vremise|number_format(2, ',', ' ') }}</td>
                        {% endif %}
                        <td style=\"text-align: center\">{{ bon.vtva|number_format(2, ',', ' ') }}</td>
                        <td style=\"text-align: center\">{{ bon.totalttc|number_format(2, ',', ' ') }}</td>
                    </tr>
                </table>
                <table class=\"table-bordered\" style=\"float: right; width: 38% ; margin-top: 10px\">
                    <tr style=\"font-weight: 600\">
                        <td style=\"text-align: center ;  background-color: #f8f9fa; font-weight: 700\">SOMME
                            RECUE
                        </td>
                        <td style=\"text-align: center ; background-color: #f8f9fa; font-weight: 700\">RESTE À
                            PAYER
                        </td>
                    </tr>
                    <tr>
                        <td style=\"text-align: center\">{{ bon.recu|number_format(2, ',', ' ') }}</td>
                        <td style=\"text-align: center\">{{ bon.reste|number_format(2, ',', ' ') }}</td>
                    </tr>
                </table>
            {% endif %}
            {% if bon.type == \"none\" %}
                <table style=\"width: 100%; margin-Top: 5px;\">
                    <tr>
                        <td style=\"text-align: left ; text-decoration: underline; border: none !important;\">VISA
                            CHEF CHANTIER
                        </td>
                        <td style=\"text-align: center ; text-decoration: underline; border: none !important;\">VISA
                            CHEF DÉPÔT
                        </td>
                        <td style=\"text-align: right ; text-decoration: underline; border: none !important;\">VISA
                            DIRECTION
                        </td>
                    </tr>
                </table>
            {% endif %}

            <p style=\"clear: both\"></p>
            <br><br>
            {% if bon.type != \"none\" %}
                <p style=\"font-weight: 700; color: #111010; text-align: left\">
                    Arrêté le présent bon à la somme de: <br><span
                            style=\"color: dimgray\"> {{ bon.totalttc|craue_spellout() }} {{ bon.monnaie.code }}</span>
                </p><br>
                <p style=\"float: right\"><u>SIGNATURE AUTORISÉE</u></p><br><br><br>
            {% endif %}
            {% if bon.conditions is not null %}
                <p style=\"float: left; color: #4e73df;\"><u>INFORMATIONS ADDITIONNELLES</u></p>
                <p style=\"clear: both\"></p>
                <p style=\"color: #000000;\">{{ bon.conditions|raw }}</p>
            {% endif %}

        </div>
    </div>
{% endif %}

{# caisse #}
{% if type == 'caisse' %}
    <div class=\"bood\">
        <div>
            <table style=\"margin-top: {{ formes.teteDB }}px !important; float:right\">
                <tr>
                    <td style=\"border: none !important; text-align: center\">
                        <b>{{ caisse.client.nomclient|upper }}</b> <br>
                        {{ caisse.client.adresse }} <br>
                    </td>
                </tr>
            </table>
            <p style=\"clear: both\"></p>
            <br>
            <table style=\"text-align: left\">
                <tr>
                    <td style=\"border: none !important; font-size: 25px\">
                        {% if caisse.type != 3 %}
                            {% if caisse.bon is same as null %}
                                <b>BON DE CAISSE - CHARGE INTERNE</b>
                            {% endif %}

                            {% if caisse.bon is not same as null %}
                                <b>BON DE CAISSE </b>
                            {% endif %}
                        {% else %}
                            <b>BON DE CAISSE - INTERNE CHANTIER</b>
                        {% endif %}
                    </td>
                </tr>
            </table>
            <p style=\"clear: both\"></p>
            <table>
                <tr style=\"background-color: #f8f9fa;  font-weight: 700\">
                    <td class=\"text-center borde\"><b>DATE</b></td>
                    {% if caisse.bon is not same as null %}
                        <td class=\"text-center borde\"><b>COMMANDE N°</b></td>
                    {% endif %}
                    <td class=\"text-center borde\"><b>CAISSE N° </b></td>
                    {% if caisse.bon is not same as null %}
                        <td class=\"text-center borde\"><b>DEVIS N°</b></td>
                    {% endif %}
                    {% if caisse.type != 3 %}
                        <td class=\"text-center borde\"><b>CHARGE INTERNE</b></td>
                    {% endif %}

                </tr>
                <tr>
                    <td class=\"text-center borde\">{{ caisse.date|date('d/m/y') }}</td>
                    {% if caisse.bon is not same as null %}
                        <td class=\"text-center borde\">{{ caisse.bon.numbon }}</td>
                    {% endif %}
                    <td class=\"text-center borde\">{{ caisse.numcaisse }}</td>
                    {% if caisse.bon is not same as null %}
                        <td class=\"text-center borde\">{{ caisse.bon.devis.iddevis }}</td>
                    {% endif %}
                    {% if caisse.intervenant is not same as null %}
                        <td class=\"text-center borde\">
                            {caisse.intervenant.nom.toUpperCase()}
                        </td>
                    {% endif %}
                    {% if caisse.personnel is not same as null %}
                        <td class=\"text-center borde\">
                            {{ caisse.personnel.noms|upper }}
                        </td>
                    {% endif %}
                    {% if caisse.fournisseur is not same as null %}
                        <td class=\"text-center borde\">
                            {{ caisse.fournisseur.fournisseur|upper }}
                        </td>
                    {% endif %}
                </tr>
                <tr>
                    <td class=\"text-left borde\" colSpan=\"5\"><span
                                style=\"text-decoration: underline ; line-height: 1.5 \"><b>RÉFÉRENCE</b></span><br/><span>{{ caisse.caissereference|raw }}</span>
                    </td>
                </tr>
            </table>
        </div>
        <br>
        <table style=\"width: 100%\">
            <tr style=\"background-color:#4e73df; color: white\">
                <th style=\"text-align: left\">DÉSIGNATION</th>
                <th class=\"text-center\">MONTANT</th>
            </tr>

            {% for lign in caisse.lignes %}
                <tr>
                    <td style=\"line-height: 1.5;text-align: left\">{{ lign.designation|raw }}</td>
                    <td style=\"text-align: right\">{{ lign.pu|number_format(2, ',', ' ') }}</td>
                </tr>
            {% endfor %}
            {% if caisse.intervenant is not null %}
                <tr>
                    <td style=\"color:red\"><b>HISTORIQUE DES PAIEMENTS</b></td>
                    <td></td>
                </tr>
                {% set recu = 0 %}
                {% for caisse in caisses %}
                    {% if caisse.etat == 'valide' %}
                        <tr>
                            <td>{{ caisse.date|date('d/m/y') }} | <span>N° Bon: {{ caisse.numcaisse }}</span> |
                                Somme reçue
                            </td>
                            <td>
                                {{ caisse.montant|number_format(2, ',', ' ') }}
                                {% set recu = caisse.montant + recu %}
                            </td>
                        </tr>
                    {% endif %}
                {% endfor %}
            {% endif %}

            {% if caisse.fournisseur is not null %}
                {% if caisse.bon.caisses is not null %}
                    <tr>
                        <td colSpan=\"2\" class=\"borde\" style=\"color: red\"><b>HISTORIQUE DES PAIEMENTS</b></td>
                    </tr>
                    {% set recu = 0 %}
                    {% for caisse in caisse.bon.caisses %}
                        {% if caisse.etat == 'valide' %}
                            <tr>
                                <td>{{ caisse.date|date('d/m/y') }} |
                                    <span>N° Bon: {{ caisse.numcaisse }}</span> |
                                    Somme reçue
                                </td>
                                <td>
                                    {{ caisse.montant|number_format(2, ',', ' ') }}
                                    {% set recu = caisse.montant + recu %}
                                </td>
                            </tr>
                        {% endif %}
                    {% endfor %}
                {% endif %}
            {% endif %}
        </table>
        <br>
        {% if caisse.intervenant is not same as null %}
            <table class=\"table-bordered\" style=\"float: left; width: 58%;\">
                <tr style=\"font-weight: 600; \">
                    <td style=\"text-align: center; background-color: #f8f9fa !important;\"
