                    </td>
                    <td style=\"text-align: center; background-color: #f8f9fa !important;\"
                    ><b>RESTE À PAYER</b>
                    </td>
                </tr>
                <tr>
                    <td style=\"text-align: center\">
                        {% if caisse.intervenant %}
                            {{ caisse.intervenant.payer|number_format(2, ',', ' ') }}
                        {% endif %}
                    </td>
                    <td align=\"center\">
                        {% if caisse.intervenant %}
                            {{ caisse.intervenant.recu|number_format(2, ',', ' ') }}
                        {% endif %}
                    </td>
                    <td align=\"center\">

                        {{ (caisse.intervenant.payer - caisse.intervenant.recu)|number_format(2, ',', ' ') }}

                    </td>
                </tr>
            </table>
        {% endif %}
        {% if caisse.bon is same as null %}
            <table class=\"table-bordered\" style=\"float: right ; width: 30% ; margin-top: 10px\">
                <tr style=\"font-weight: 600\">
                    <td class=\"borde\" style=\"text-align: center; background-color: #f8f9fa\"><b>MONTANT À DÉCAISSER</b>
                    </td>
                </tr>
                <tr>
                    <td class=\"borde\" style=\"text-align: center\">{{ caisse.montant|number_format(2, ',', ' ') }}</td>
                </tr>
            </table>
        {% endif %}
        {% if caisse.fournisseur is not same as null %}
            <table class=\"table-bordered\" style=\"float: left ; width: 60% ; margin-top: 10px\">
