                    <td class=\"borde\" style=\"text-align: center; background-color: #f8f9fa\"><b>TTC BON COMMANDE</b></td>
                    <td class=\"borde\" style=\"text-align: center; background-color: #f8f9fa\"><b>SOMME PAYÉE</b></td>
                    <td class=\"borde\" style=\"text-align: center; background-color: #f8f9fa\"><b>RESTE À PAYER</b></td>
                </tr>
                <tr>
                    <td class=\"borde\"
                        style=\"text-align: center\">{{ caisse.bon.totalttc|number_format(2, ',', ' ') }}</td>
                    <td class=\"borde\" style=\"text-align: center\">{{ caisse.bon.recu|number_format(2, ',', ' ') }}</td>
                    <td class=\"borde\" style=\"text-align: center\">{{ caisse.bon.reste|number_format(2, ',', ' ') }}</td>
                </tr>
            </table>
            <table class=\"table-bordered\" style=\"width: 38% ; float: right ; margin-top: 10px\">
                <tr style=\"font-weight: 600\">
                    <td class=\"borde\" style=\"text-align: center; background-color: #f8f9fa\"><b>MONTANT TOTAL</b>
                    </td>
                    <td class=\"borde\" style=\"text-align: center; background-color: #f8f9fa\"><b>MONTANT À PAYER</b></td>
                </tr>
                <tr style=\"color: black\">
                    <td class=\"borde\" style=\"text-align: center\">{{ caisse.total|number_format(2, ',', ' ') }}</td>
                    <td class=\"borde\" style=\"text-align: center\">{{ caisse.montant|number_format(2, ',', ' ') }}</td>
                </tr>
            </table>
        {% endif %}
        <br><br><br>
        <table style=\"margin-top:20px; float: right\">
            <tr>
                <br style=\"border: none !important; text-align: left\">
                <b>Arrêté le présent bon à la somme de</b>:<span
                        style=\"color: dimgray\"> {{ (caisse.montant|number_format(2, '.', ''))|craue_spellout() }}&nbsp;{% if caisse.monnaie %}{{ caisse.monnaie.code }} {% endif %}</span>
                </td>
            </tr>
        </table>
        `
        <br><br><br><br><br>
        <table style=\"width: 100%\">
