                        {% endif %}
                        <th style=\"text-align: center\">MONTANT&nbsp;HT</th>
                        <th style=\"text-align: center\">%</th>
                        <th style=\"text-align: center\">VALEUR</th>
                    </tr>

                    {% for group in listGroup %}
                        <tr class=\"togo\">
                            {% if devis.zone == 'oui' and devis.aarem == 'oui' %}
                                {% if devis.aaref == 'oui' %}
                                    <td style=\"text-align: center\"><b>{{ group.reference }}</b></td>
                                {% endif %}
                                <td colspan=\"9\"><b>{{ group.groupe|striptags|raw }}</b></td>

                            {% elseif devis.zone == 'non' and devis.aarem == 'non' %}
                                {% if devis.aaref == 'oui' %}
                                    <td style=\"text-align: center\"><b>{{ group.reference }}</b></td>
                                {% endif %}
                                <td colspan=\"7\"><b>{{ group.groupe|striptags|raw }}</b></td>

                            {% elseif devis.zone == 'oui' and devis.aarem == 'non' %}
                                {% if devis.aaref == 'oui' %}
                                    <td style=\"text-align: center\"><b>{{ group.reference }}</b></td>
                                {% endif %}
                                <td colspan=\"8\"><b>{{ group.groupe|striptags|raw }}</b></td>

                            {% elseif devis.aarem == 'oui' and devis.zone == 'non' %}
                                {% if devis.aaref == 'oui' %}
                                    <td style=\"text-align: center\"><b>{{ group.reference }}</b></td>
                                {% endif %}
                                <td colspan=\"8\"><b>{{ group.groupe|striptags|raw }}</b></td>
                            {% endif %}
                        </tr>
                        {% set st = 0 %}
                        {% for lign in decompte.lignes %}
                            {% if lign.groupe == group %}
                                <tr>
                                    {% if devis.aaref == 'oui' %}
                                        <td style=\"text-align: center\">{{ lign.reference }}</td>
                                    {% endif %}
                                    <td style=\"text-align: left\">{{ lign.designation|raw }}</td>
                                    {% if devis.zone == 'oui' %}
                                        <td style=\"text-align: center\">{{ lign.zone }}</td>
                                    {% endif %}
                                    <td style=\"text-align: center\">{{ lign.unite }}</td>
                                    <td style=\"text-align: center\">{{ lign.quantite }}</td>
                                    <td style=\"text-align: right; white-space: nowrap\">{{ lign.pu|number_format(2, ',', ' ') }}</td>
                                    {% if devis.aarem == 'oui' %}
                                        <td style=\"text-align: center\">{{ lign.remise }}%</td>
                                    {% endif %}
