                                    {% else %}
                                        <td style=\"text-align: right; white-space: nowrap\">{% set st = ((lign.pu * lign.quantite)*((100 - lign.remise)/100)) + st %}{{ ((lign.pu * lign.quantite)*((100 - lign.remise)/100))|number_format(2, ',', ' ') }}</td>
                                    {% endif %}
                                    <td style=\"text-align: center; white-space: nowrap\">{{ lign.avancement|number_format(2, ',', ' ') }}
                                        %
                                    </td>

                                    {% if devis.aarem == 'non' %}
