                                    {% else %}
                                        <td style=\"text-align: right; white-space: nowrap\">{{ ((((lign.pu * lign.quantite)*((100 - lign.remise)/100))* lign.avancement)/100)|number_format(2, ',', ' ') }}</td>
                                    {% endif %}
                                </tr>
                            {% endif %}
                        {% endfor %}
