                                    % {% if devis.ptva == 'non' %} (Non facturée) {% endif %}{% if devis.ptva == 'susp' %} (Suspendue) {% endif %}:
                                </td>
                            {% else %}
                                <td class=\"bord\" colspan=\"5\"
                                    style=\"font-weight: bold\">TVA {{ devis.tva }}
                                    % {% if devis.ptva == 'non' %} (Non facturée) {% endif %}{% if devis.ptva == 'susp' %} (Suspendue) {% endif %}:
                                </td>
                            {% endif %}
