                                    % {% if devis.ptva == 'non' %} (Non facturée) {% endif %}{% if devis.ptva == 'susp' %} (Suspendue) {% endif %}:
                                </td>
                            {% else %}
                                <td class=\"bord\" colspan=\"4\"
                                    style=\"font-weight: bold\">TVA {{ devis.tva }}
                                    % {% if devis.ptva == 'non' %} (Non facturée) {% endif %}{% if devis.ptva == 'susp' %} (Suspendue) {% endif %}:
                                </td>
                            {% endif %}
                        {% endif %}

                        <td style=\"text-align: right\"></td>
                        <td style=\"text-align: center\"></td>
                        <td style=\"text-align: right; font-weight: bold; white-space: nowrap\">{{ ((decompte.apayer * devis.tva)/100)|number_format(2, ',', ' ') }}</td>
                    </tr>
                    <tr>
                        {% if devis.zone == 'oui' and  devis.aarem != 'oui' %}
                            {% if devis.aaref == 'oui' %}
                                <td class=\"bord\" colspan=\"6\"
                                    style=\"font-weight: bold\">TOTAL TTC DÉCOMPTE
                                    N°:{{ decompte.numdecompte }}
                                </td>
                            {% else %}
                                <td class=\"bord\" colspan=\"5\"
                                    style=\"font-weight: bold\">TOTAL TTC DÉCOMPTE
                                    N°:{{ decompte.numdecompte }}
                                </td>
                            {% endif %}
                        {% endif %}


                        {% if devis.aarem == 'oui' and devis.zone != 'oui' %}
                            {% if devis.aaref == 'oui' %}
                                <td class=\"bord\" colspan=\"6\"
                                    style=\"font-weight: bold\">TOTAL TTC DÉCOMPTE
                                    N°:{{ decompte.numdecompte }}
                                </td>
                            {% else %}
                                <td class=\"bord\" colspan=\"5\"
                                    style=\"font-weight: bold\">TOTAL TTC DÉCOMPTE
                                    N°:{{ decompte.numdecompte }}
                                </td>
                            {% endif %}
                        {% endif %}


                        {% if devis.zone == 'oui' and  devis.aarem == 'oui' %}
                            {% if devis.aaref == 'oui' %}
                                <td class=\"bord\" colspan=\"7\"
                                    style=\"font-weight: bold\">TOTAL TTC DÉCOMPTE
                                    N°:{{ decompte.numdecompte }}
                                </td>
                            {% else %}
                                <td class=\"bord\" colspan=\"6\"
                                    style=\"font-weight: bold\">TOTAL TTC DÉCOMPTE
                                    N°:{{ decompte.numdecompte }}
                                </td>
                            {% endif %}
                        {% endif %}

                        {% if devis.zone != 'oui' and  devis.aarem != 'oui' %}
